-- Task Queue indexes (most queried table)
CREATE INDEX IF NOT EXISTS idx_task_status ON ai_task_queue(taskStatus);
CREATE INDEX IF NOT EXISTS idx_task_status_completed ON ai_task_queue(taskStatus, taskCompletedAt);
CREATE INDEX IF NOT EXISTS idx_task_created ON ai_task_queue(taskCreatedAt);
CREATE INDEX IF NOT EXISTS idx_task_priority_status ON ai_task_queue(taskPriority, taskStatus);
CREATE INDEX IF NOT EXISTS idx_task_subsystem ON ai_task_queue(taskSubsystem);

-- Decisions indexes
CREATE INDEX IF NOT EXISTS idx_decision_cycle ON ai_decisions(decisionCycle);
CREATE INDEX IF NOT EXISTS idx_decision_subsystem ON ai_decisions(decisionSubsystem);
CREATE INDEX IF NOT EXISTS idx_decision_created ON ai_decisions(decisionCreatedAt);

-- Metrics indexes
CREATE INDEX IF NOT EXISTS idx_metrics_date ON ai_metrics(metricDate);
CREATE INDEX IF NOT EXISTS idx_metrics_type_date ON ai_metrics(metricType, metricDate);

-- SEO Projects indexes (frequently queried)
CREATE INDEX IF NOT EXISTS idx_seo_projects_status ON seo_projects(status);
CREATE INDEX IF NOT EXISTS idx_seo_projects_user ON seo_projects(userId);

-- Rank Tracking indexes
CREATE INDEX IF NOT EXISTS idx_rank_tracking_project ON rank_tracking(projectId);
CREATE INDEX IF NOT EXISTS idx_rank_tracking_tracked ON rank_tracking(trackedAt);

-- Deploy History indexes
CREATE INDEX IF NOT EXISTS idx_deploy_status ON deploy_history(status);
CREATE INDEX IF NOT EXISTS idx_deploy_created ON deploy_history(createdAt);

-- PBN Sites indexes
CREATE INDEX IF NOT EXISTS idx_pbn_sites_status ON pbn_sites(status);

-- Scheduled Scans indexes
CREATE INDEX IF NOT EXISTS idx_scans_enabled ON scheduled_scans(enabled);
CREATE INDEX IF NOT EXISTS idx_scans_next_run ON scheduled_scans(nextRunAt);

